    ('BBG000QCW561', DATE '2019-12-31', 2.5300000000000002)
),
resolved AS (
    SELECT
        i.id AS instrument_id,
        s.trade_date,
        s.price::numeric(18,4) AS price,
        i.currency_id,
        md5(i.id::text || '|' || s.trade_date::text || '|TBANK') AS hash_key
    FROM src s
    JOIN instruments i ON upper(i.figi) = s.figi
)
INSERT INTO prices (id, instrument_id, date, value, currency_id, provider, created_at, updated_at)
SELECT
    (
        substr(hash_key, 1, 8) || '-' ||
        substr(hash_key, 9, 4) || '-' ||
        substr(hash_key, 13, 4) || '-' ||
        substr(hash_key, 17, 4) || '-' ||
        substr(hash_key, 21, 12)
    )::uuid,
    instrument_id,
    (trade_date::timestamp AT TIME ZONE 'UTC'),
    price,
    currency_id,
    'TBANK',
    now(),
    now()
FROM resolved
ON CONFLICT (instrument_id, date, provider)
DO UPDATE
SET value = EXCLUDED.value,
    currency_id = EXCLUDED.currency_id,
    updated_at = now();

COMMIT;

-- ===== END scripts/tbank_history/sql/prices_2019.sql =====


DO $$
DECLARE
    expected_moex bigint := 32040;
    expected_tbank bigint := 252;
    actual_moex bigint;
    actual_tbank bigint;
    actual_total bigint;
BEGIN
    WITH scoped AS (
        SELECT provider, count(*) AS rows_count
        FROM prices
        WHERE date >= TIMESTAMP '2019-01-01 00:00:00+00'
          AND date < TIMESTAMP '2020-01-01 00:00:00+00'
          AND upper(provider) IN ('MOEX', 'TBANK')
        GROUP BY provider
    )
    SELECT
        COALESCE(max(CASE WHEN upper(provider) = 'MOEX' THEN rows_count END), 0),
        COALESCE(max(CASE WHEN upper(provider) = 'TBANK' THEN rows_count END), 0),
        COALESCE(sum(rows_count), 0)
    INTO actual_moex, actual_tbank, actual_total
    FROM scoped;

    IF actual_moex <> expected_moex THEN
        RAISE EXCEPTION 'Consolidated 2019 validation failed: expected MOEX %, got %.', expected_moex, actual_moex;
    END IF;

    IF actual_tbank <> expected_tbank THEN
        RAISE EXCEPTION 'Consolidated 2019 validation failed: expected TBANK %, got %.', expected_tbank, actual_tbank;
    END IF;

    IF actual_total <> expected_moex + expected_tbank THEN
        RAISE EXCEPTION 'Consolidated 2019 validation failed: expected total %, got %.', expected_moex + expected_tbank, actual_total;
    END IF;

    RAISE NOTICE 'Consolidated 2019 validation passed. MOEX: %, TBANK: %, total: %.', actual_moex, actual_tbank, actual_total;
END $$;
